namespace NotificationApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
        new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-15)),
        new(3, "New feature: dark mode is available.", DateTime.UtcNow.AddMinutes(-5)),
    ];

    private static readonly string[] Templates =
    [
        "Server health check passed.",
        "New comment on your post.",
        "Deployment completed successfully.",
        "Backup finished.",
        "User signed up.",
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        // Randomly add a new notification ~40% of the time
        if (Random.Shared.NextDouble() < 0.4)
        {
            var msg = Templates[Random.Shared.Next(Templates.Length)];
            lock (_notifications)
            {
                _notifications.Add(new(_nextId++, msg, DateTime.UtcNow));
            }
        }

        lock (_notifications)
        {
            var newer = _notifications
                .Where(n => n.Timestamp > since)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(newer);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationApp.Services
@inject NotificationService NotificationService
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="notification-list">
        @foreach (var n in notifications)
        {
            <li>
                <strong>@n.Message</strong>
                <small>@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we don't re-fetch data already restored from prerender
        notifications ??= await NotificationService.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender never runs during prerender, so the polling
            // loop only starts once the page is live and interactive.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var since = notifications?.MaxBy(n => n.Timestamp)?.Timestamp ?? DateTime.MinValue;
            var newer = await NotificationService.GetNotificationsSinceAsync(since);

            if (newer.Count > 0 && notifications is not null)
            {
                notifications.InsertRange(0, newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

h1 {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.badge {
    background-color: #0d6efd;
    color: white;
    font-size: 0.75rem;
    font-weight: 600;
    padding: 0.25em 0.6em;
    border-radius: 999px;
}

