+++ b/tmp/sv-4549c6828f80431fbac3b02e2c1093e9/NotificationApp/Components/Pages/Notifications.razor
@@ -1,0 +1,87 @@
+@page "/notifications"
+@rendermode InteractiveServer
+@using NotificationApp.Services
+@inject NotificationService NotificationService
+@implements IAsyncDisposable
+
+<PageTitle>Notifications</PageTitle>
+
+<h1>
+    Notifications
+    @if (notifications is not null)
+    {
+        <span class="badge">@notifications.Count</span>
+    }
+</h1>
+
+@if (notifications is null)
+{
+    <p><em>Loading notifications…</em></p>
+}
+else if (notifications.Count == 0)
+{
+    <p>No notifications.</p>
+}
+else
+{
+    <ul class="notification-list">
+        @foreach (var n in notifications)
+        {
+            <li>
+                <strong>@n.Message</strong>
+                <small>@n.Timestamp.ToString("HH:mm:ss")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private CancellationTokenSource? _cts;
+
+    [PersistentState]
+    public List<Notification>? notifications { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        // ??= ensures we don't re-fetch data already restored from prerender
+        notifications ??= await NotificationService.GetNotificationsAsync();
+    }
+
+    protected override void OnAfterRender(bool firstRender)
+    {
+        if (firstRender)
+        {
+            // OnAfterRender never runs during prerender, so the polling
+            // loop only starts once the page is live and interactive.
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            await Task.Delay(TimeSpan.FromSeconds(5), ct);
+
+            var since = notifications?.MaxBy(n => n.Timestamp)?.Timestamp ?? DateTime.MinValue;
+            var newer = await NotificationService.GetNotificationsSinceAsync(since);
+
+            if (newer.Count > 0 && notifications is not null)
+            {
+                notifications.InsertRange(0, newer);
+                await InvokeAsync(StateHasChanged);
+            }
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        if (_cts is not null)
+        {
+            await _cts.CancelAsync();
+            _cts.Dispose();
+        }
+    }
+}
+

